            jQuery('.council_exam_no').val(council_exam_no);
            jQuery('.remarks').val('');
            jQuery('.fee_submission_date').val('<?php echo date('Y-m-d')?>');
            jQuery('.fee_submission_dates').attr('data-date', '<?php echo date('Y-m-d')?>');
        });
        jQuery('.add_remarks_button').click(function(){
            var student_id = jQuery('.student_id').val();
            var council_exam_no = jQuery('.council_exam_no').val();
            var fee_submission_date = jQuery('.fee_submission_date').val();
            var amount = jQuery('.amount').val();
            var next_admission = jQuery('input[name=next_admission]:checked').val();
            var student_status = jQuery('input[name=student_status]:checked').val();
            var clas = jQuery('input[name=class]:checked').val();
            var remarks = jQuery('.remarks').val();
            jQuery.ajax({
                type: "post",
                async: false,
                url: '<?php echo site_url()?>/next_council_admissions/add_manual_remarks',
                data: {
                    student_id : student_id,
                    council_exam_no : council_exam_no,
                    clas : clas,
                    fee_submission_date : fee_submission_date,
                    amount : amount,
                    next_admission : next_admission,
                    student_status : student_status,
                    remarks : remarks
                },
                success: function(data) {
                    jQuery('.close_button').trigger('click');
                }

            });
        });
        jQuery('.next_admission').change(function(){
            var okadmission = jQuery("input[name='next_admission']:checked").val();
            if(okadmission==1)
            {
                jQuery('.okadmission').show();
            }
            else
            {
                jQuery('.okadmission').hide();
            }
        });
        jQuery('.delete_student').click(function(){
            var student_id = jQuery(this).data('student-id');
            jQuery('.student_id').val(student_id);
            var student_fee_submit = jQuery(this).data('student-submit-fee');
            jQuery('.refund_amount').attr('max',student_fee_submit);
        });
    });
</script>
