                    purchaser_student_id :purchaser_student_id
                },
                success: function(data) {
                    jQuery('.product_price_'+position).html(data);
                    if(data==0)
                    {
                        jQuery('.product_quantity_'+position).attr('max','1');
                        jQuery('.product_quantity_'+position).val(1);
                        jQuery('.product_quantity_'+position).trigger('change');
                        jQuery('.note_'+position).html('(Free Product)');
                    }
                    else if(data=='')
                    {
                        jQuery('.product_quantity_'+position).removeAttr('max');
                        jQuery('.product_quantity_'+position).trigger('change');
                        jQuery('.note_'+position).html('');
                    }
                    else
                    {
                        jQuery('.product_quantity_'+position).removeAttr('max');
                        jQuery('.product_quantity_'+position).trigger('change');
                        jQuery('.note_'+position).html('');
                    }
                }
            });
        });

        jQuery('.product_quantity').live('change',function(){
            var position = jQuery(this).data('row-id');
            var quantity = jQuery(this).val();
            var campus_id = jQuery('.campus_id_'+position+'').select2('val');
            var room_id = jQuery('.room_id_'+position+'').select2('val');
            var subroom_id = jQuery('.subroom_id_'+position+'').select2('val');
            var product_name_id = jQuery('.product_name_id_'+position+'').select2('val');
            if(campus_id=='' || room_id=='' || product_name_id=='')
            {
                alert('Kindly Select Complete Options before adding quantity');
                jQuery(this).val('');
            }
            else
            {
                //CHECK SAME PRODUCT ADDED ABOVE
                if(position>1)
                {
                    var total_items = jQuery('.item').length;
                    //alert(total_items);
                    
                    for(i=1;i<=total_items;i++)
                    {
                        if(jQuery('.campus_id_'+i).select2('val')==campus_id && jQuery('.room_id_'+i).select2('val')==room_id && jQuery('.subroom_id_'+i).select2('val')==subroom_id && jQuery('.product_name_id_'+i).select2('val')==product_name_id && i!=position)
                        {
                            alert('You cannot add same product twice.');
                            jQuery('.product_quantity_'+position).val('0');
                            jQuery('.product_name_id_'+position).select2('val','');
                            jQuery('.product_name_id_'+position).trigger('change');
                            jQuery('.product_price_'+position).html('');
                            jQuery('.note_'+position).empty();
                            jQuery('.product_subtotal_'+position).empty();
                        }
                    }
                }
                //CHECK PRODUCT AVAILABLE OR Not
                jQuery.ajax({
                    type: "post",
                    async: false,
                    url: '<?php echo site_url()?>/pos/checkProductAvailblity',
                    data: {
                        campus_id : campus_id,
                        room_id : room_id,
                        subroom_id : subroom_id,
                        product_name_id : product_name_id,
                        quantity : quantity
                    },
                    success: function(data) {
                        if(data=='failed')
                        {
                            alert('Selected Product is not available on your selected location.');
                            jQuery('.product_quantity_'+position).val('');
                        }
                        else if(data=='outofstock')
                        {
                            alert('There is not enough quantity of product on your given location');
                            jQuery('.product_quantity_'+position).val('');
                        }
                        else
                        {

                        }
                    }
                });
            }
            var price = jQuery('.product_price_'+position).html();
            var subtotal = price*quantity;
            jQuery('.product_subtotal_'+position).html(subtotal);
            calculateTotal();
        });
        
        function calculateTotal() {
            let total = 0;
    
            jQuery(".product_subtotal").each(function () {
                let price = parseFloat(jQuery(this).text().replace(/,/g, '')) || 0; 
                total += price;
            });
    
            jQuery(".pay_now").data('amount',total); // show with 2 decimal places
        }

